// Normaliza el payload entrante de Zolutium. El webhook entrega:
//   { contact_id, marca, canal_preferido, evento, fired_at }
// Validamos lo minimo, derivamos identificadores y armamos las idempotency keys.
// Si llegamos desde Manual Trigger sin body, usamos un payload mock para pruebas.
const incoming = $input.first().json || {};
let body = incoming.body || incoming;
if (!body || (!body.contact_id && !body.contactId && !body.id)) {
  body = {
    contact_id: 'mock-contact-uuid-0001',
    marca: 'glass-soler',
    canal_preferido: 'email',
    __mock: true
  };
}
const contactId = body.contact_id || body.contactId || body.id;
const marca = (body.marca || body.brand || '').toLowerCase();
const canalPreferido = (body.canal_preferido || body.preferred_channel || 'email').toLowerCase();

if (!contactId) {
  throw new Error('Payload sin contact_id: ' + JSON.stringify(body).slice(0, 300));
}
if (!['glass-soler', 'esmeralda'].includes(marca)) {
  throw new Error(`Marca invalida '${marca}'. Esperado: glass-soler | esmeralda`);
}
if (!['email', 'whatsapp', 'sms', 'push'].includes(canalPreferido)) {
  throw new Error(`canal_preferido invalido '${canalPreferido}'`);
}

const recibidoEn = new Date().toISOString();
return [{
  json: {
    contact_id: contactId,
    marca,
    canal_preferido: canalPreferido,
    recibido_en: recibidoEn,
    es_mock: !!body.__mock,
    idem_message: `welcome-${contactId}`,
    idem_grant: `welcome-grant-${contactId}`,
    idem_audit: `welcome-audit-${contactId}`
  }
}];

// D2 — Sanitizacion PII antes de enviar a Claude.
// Hasheamos el contact_id y NUNCA exponemos email/telefono/nombre/documento.
// Solo enviamos atributos no PII: segmento, tier inicial, idioma, marca, canal.
const crypto = require('crypto');
const init = $('Init onboarding (validar payload)').first().json;
const contacto = $input.first().json || {};
const salt = $env.PII_SALT || 'bac-loyalty';
const hashId = id => crypto.createHash('sha256').update(String(id) + salt).digest('hex').slice(0, 12);

const beneficiosPorTier = {
  bronze: ['1x acumulacion de puntos', 'acceso a catalogo basico', 'invitaciones a sorteos mensuales'],
  silver: ['1.25x acumulacion', 'descuentos exclusivos 5%', 'soporte prioritario'],
  gold: ['1.5x acumulacion', 'descuentos exclusivos 10%', 'eventos VIP', 'cumpleanos doble puntos'],
  platinum: ['2x acumulacion', 'descuentos exclusivos 15%', 'concierge dedicado', 'experiencias premium']
};

const tier = (contacto.tier || 'bronze').toLowerCase();
const segmento = contacto.segment || 'new';
const idioma = (contacto.language || 'es').toLowerCase();

const payloadIA = {
  id_hash: hashId(init.contact_id),
  marca: init.marca,
  canal_preferido: init.canal_preferido,
  tier_inicial: tier,
  segmento,
  idioma,
  beneficios_tier: beneficiosPorTier[tier] || beneficiosPorTier.bronze,
  puntos_bienvenida: 100,
  pii_sanitized: true
};

return [{
  json: {
    ...init,
    payload_ia: payloadIA,
    tier_inicial: tier,
    segmento,
    idioma
  }
}];

// Validacion robusta de la salida de Claude (D5).
// Extrae JSON aunque venga envuelto en markdown o con texto antes/despues.
const raw = $input.first().json?.content?.[0]?.text
         || $input.first().json?.text
         || $input.first().json?.message?.content
         || '';

function extractJson(s) {
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenced) return fenced[1].trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start >= 0 && end > start) return s.slice(start, end + 1);
  return s;
}

const ctx = $('Sanitizar PII (preparar prompt)').first().json;

let mensaje;
try {
  mensaje = JSON.parse(extractJson(raw));
} catch (e) {
  return [{
    json: {
      ...ctx,
      __invalid_json: true,
      raw_excerpt: raw.slice(0, 500),
      error: e.message,
      descartar: true,
      confianza: 0
    }
  }];
}

const confianza = Number(mensaje.confianza ?? 0);
const umbral = Number($env.KB_CONFIDENCE_THRESHOLD || 0.6);
const tieneCampos = !!(mensaje.asunto && mensaje.cuerpo_markdown && mensaje.cta_url);
const descartar = !tieneCampos || confianza < umbral || !!mensaje.error;

return [{
  json: {
    ...ctx,
    asunto: mensaje.asunto || null,
    cuerpo_markdown: mensaje.cuerpo_markdown || null,
    cta_url: mensaje.cta_url || null,
    confianza,
    descartar,
    generado_en: new Date().toISOString()
  }
}];

// Rama de descarte: registramos sin enviar mensaje ni otorgar puntos.
const j = $input.first().json;
console.log('[Agente-11] Bienvenida descartada:', JSON.stringify({
  contact_id_hash: j.payload_ia?.id_hash,
  marca: j.marca,
  invalid_json: !!j.__invalid_json,
  confianza: j.confianza,
  error: j.error
}));
return [{ json: j }];
